# PREPROCESSING FUNCTIONS
def cleaning(text: str) -> str:
    text = str(text)
    text = re.sub(r'http\S+|www\S+', '', text)
    text = re.sub(r'<.*?>', '', text)
    text = re.sub(r'[^a-zA-Z\s]', ' ', text)
    text = re.sub(r'\s+', ' ', text).strip()
    return text

def case_folding(text: str) -> str:
    return text.lower()

def tokenizing(text: str) -> list:
    return text.split()

def stopword_removal(tokens: list, sw: set) -> list:
    return [t for t in tokens if t not in sw and len(t) > 2]

def stemming_tokens(tokens: list, stemmer, cache: dict) -> list:
    result = []
    for t in tokens:
        if t not in cache:
            cache[t] = stemmer.stem(t)
        result.append(cache[t])
    return result

def full_preprocessing(text: str, stemmer, sw: set, cache: dict, do_stem: bool = True) -> list:
    text = cleaning(text)
    text = case_folding(text)
    toks = tokenizing(text)
    toks = stopword_removal(toks, sw)
    if do_stem:
        toks = stemming_tokens(toks, stemmer, cache)
    return [t for t in toks if len(t) > 2]

