def plot_k_optimal_static():
    k_vals        = [2, 3, 4, 5, 6, 7, 8]
    lda_cvs       = [0.4484, 0.6126, 0.6012, 0.6301, 0.6139, 0.6091, 0.5864]
    nmf_cvs       = [0.6971, 0.7934, 0.7645, 0.7465, 0.7680, 0.7921, 0.7656]
    log_perp_lda  = [7.7355, 7.6340, 7.5664, 7.4932, 7.4676, 7.4453, 7.4225]
    chosen_k      = 4
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(13, 4))
    fig.patch.set_facecolor("#f8f9ff")
    ax1.plot(k_vals, lda_cvs, "o-", color=BLUE,   lw=2, ms=7, label="LDA")
    ax1.plot(k_vals, nmf_cvs, "s-", color=ORANGE, lw=2, ms=7, label="NMF")
    ax1.axvline(chosen_k, color="red", ls="--", alpha=0.65, label=f"K={chosen_k} dipilih")
    ax1.set_title("Topic Coherence (Cv) vs K", fontweight="bold")
    ax1.set_xlabel("Jumlah Topik (K)"); ax1.set_ylabel("Coherence Cv")
    ax1.set_xticks(k_vals); ax1.legend(fontsize=9); set_ax_style(ax1)
    for k, v in zip(k_vals, lda_cvs):
        ax1.annotate(f"{v:.4f}", (k, v), textcoords="offset points", xytext=(-4, 9), ha="center", fontsize=7.5, color=BLUE)
    for k, v in zip(k_vals, nmf_cvs):
        ax1.annotate(f"{v:.4f}", (k, v), textcoords="offset points", xytext=(0, -14), ha="center", fontsize=7.5, color=ORANGE)
    ax2.plot(k_vals, log_perp_lda, "o-", color=BLUE, lw=2, ms=7, label="Log-Perplexity LDA")
    ax2.axvline(chosen_k, color="red", ls="--", alpha=0.65, label=f"K={chosen_k} dipilih")
    ax2.set_title("Log-Perplexity LDA vs K\n(↓ semakin kecil = semakin baik)", fontweight="bold")
    ax2.set_xlabel("Jumlah Topik (K)"); ax2.set_ylabel("Log-Perplexity (positif)")
    ax2.set_xticks(k_vals); ax2.legend(fontsize=9); set_ax_style(ax2)
    for k, v in zip(k_vals, log_perp_lda):
        ax2.annotate(f"{v:.4f}", (k, v), textcoords="offset points", xytext=(0, 9), ha="center", fontsize=7.5, color=BLUE)
    plt.tight_layout()
    return fig

def plot_coherence_comparison(coh_lda, coh_nmf, coh_lda_list, coh_nmf_list, n):
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(13, 4))
    fig.patch.set_facecolor("#f8f9ff")
    labels = [f"Topik {i+1}" for i in range(n)]
    x, w   = np.arange(n), 0.35
    b1 = ax1.bar(x - w/2, coh_lda_list[:n], w, label="LDA", color=BLUE,   alpha=0.85)
    b2 = ax1.bar(x + w/2, coh_nmf_list[:n], w, label="NMF", color=ORANGE, alpha=0.85)
    ax1.set_xticks(x); ax1.set_xticklabels(labels, fontsize=9)
    ax1.set_ylabel("Coherence (Cv)"); ax1.set_title("Coherence per Topik", fontweight="bold")
    ax1.legend(); ax1.set_ylim(0, max(max(coh_lda_list[:n]), max(coh_nmf_list[:n])) * 1.3)
    set_ax_style(ax1)
    for b in b1:
        ax1.text(b.get_x()+b.get_width()/2, b.get_height()+0.01, f"{b.get_height():.3f}", ha="center", fontsize=8, color=BLUE, fontweight="600")
    for b in b2:
        ax1.text(b.get_x()+b.get_width()/2, b.get_height()+0.01, f"{b.get_height():.3f}", ha="center", fontsize=8, color=ORANGE, fontweight="600")
    bars = ax2.bar(["LDA", "NMF"], [coh_lda, coh_nmf], color=[BLUE, ORANGE], width=0.4, alpha=0.85)
    ax2.set_ylabel("Rata-rata Coherence (Cv)")
    ax2.set_title("Rata-rata Coherence Keseluruhan", fontweight="bold")
    ax2.set_ylim(0, max(coh_lda, coh_nmf) * 1.3); set_ax_style(ax2)
    for b in bars:
        ax2.text(b.get_x()+b.get_width()/2, b.get_height()+0.008, f"{b.get_height():.4f}", ha="center", fontsize=13, fontweight="bold")
    plt.tight_layout()
    return fig

def plot_topic_words(model_type, topics_words, coh_list):
    n    = len(topics_words)
    rows = (n + 1) // 2
    fig, axes = plt.subplots(rows, 2, figsize=(14, rows * 3.5))
    fig.patch.set_facecolor("#f8f9ff")
    axes_flat = axes.flatten() if n > 1 else [axes]
    cmap  = "Blues_r"   if model_type == "LDA" else "Oranges_r"
    color = BLUE        if model_type == "LDA" else ORANGE
    for i, (words, weights) in enumerate(topics_words):
        ax  = axes_flat[i]
        wr  = list(reversed(words[:10]))
        wts = list(reversed(weights[:10]))
        cb  = plt.cm.get_cmap(cmap)(np.linspace(0.3, 0.85, len(wr)))
        ax.barh(wr, wts, color=cb)
        cv  = coh_list[i] if i < len(coh_list) else 0
        ax.set_title(f"{model_type} — Topik {i+1}  |  Cv = {cv:.4f}", fontweight="bold", color=color, fontsize=10)
        set_ax_style(ax)
    for j in range(len(topics_words), len(axes_flat)):
        axes_flat[j].axis("off")
    plt.tight_layout()
    return fig

def plot_wordcloud(topics_words, model_type):
    n    = len(topics_words)
    rows = (n + 1) // 2
    fig, axes = plt.subplots(rows, 2, figsize=(14, rows * 4))
    fig.patch.set_facecolor("white")
    cmap      = "Blues" if model_type == "LDA" else "Oranges"
    axes_flat = axes.flatten() if n > 1 else [axes]
    for i, (words, weights) in enumerate(topics_words):
        ax = axes_flat[i]
        wf = {w: float(v) for w, v in zip(words, weights)}
        wc = WordCloud(width=500, height=300, background_color="white",
                       colormap=cmap, max_words=30, prefer_horizontal=0.9).generate_from_frequencies(wf)
        ax.imshow(wc, interpolation="bilinear")
        ax.axis("off")
        ax.set_title(f"{model_type} — Topik {i+1}", fontweight="bold",
                     color=BLUE if model_type == "LDA" else ORANGE)
    for j in range(n, len(axes_flat)):
        axes_flat[j].axis("off")
    plt.tight_layout()
    return fig

def plot_stemming_comparison(results: dict):
    labels   = ["Dengan Stemming", "Tanpa Stemming"]
    lda_vals = [results["Dengan Stemming"]["LDA_Coherence"], results["Tanpa Stemming"]["LDA_Coherence"]]
    nmf_vals = [results["Dengan Stemming"]["NMF_Coherence"], results["Tanpa Stemming"]["NMF_Coherence"]]
    fig, axes = plt.subplots(1, 2, figsize=(12, 4))
    fig.patch.set_facecolor("#f8f9ff")
    for ax, vals, label, color in [
        (axes[0], lda_vals, "LDA", BLUE),
        (axes[1], nmf_vals, "NMF", ORANGE),
    ]:
        bars = ax.bar(labels, vals, color=color, alpha=0.85, width=0.4)
        ax.set_title(f"Coherence (Cv) {label}: Stemming vs Tanpa Stemming", fontweight="bold", fontsize=10)
        ax.set_ylabel("Coherence (Cv)")
        ax.set_ylim(0, max(vals) * 1.3); set_ax_style(ax)
        for b in bars:
            ax.text(b.get_x()+b.get_width()/2, b.get_height()+0.005, f"{b.get_height():.4f}", ha="center", fontsize=12, fontweight="bold")
    plt.tight_layout()
    return fig

