    st.markdown('<div class="section-header">Text Preprocessing</div>', unsafe_allow_html=True)
    st.markdown('<div class="info-box"><b>Pipeline Preprocessing (sesuai penelitian):</b></div>', unsafe_allow_html=True)
    cols_pipe = st.columns(5)
    steps = [
        ("1", "Cleaning", "Hapus URL, HTML, karakter non-huruf"),
        ("2", "Case Folding", "Ubah ke huruf kecil"),
        ("3", "Tokenizing", "Pecah teks jadi token kata"),
        ("4", "Stopword Removal", "Hapus kata tidak bermakna"),
        ("5", "Stemming", "Kembalikan ke kata dasar (Sastrawi)"),
    ]
    for col, (num, title, desc) in zip(cols_pipe, steps):
        col.markdown(
            f'<div class="pipeline-step"><div class="step-num">{num}</div>'
            f'<div class="step-text"><b>{title}</b><br><span style="font-size:0.78rem;color:#555">{desc}</span></div>'
            f'</div>', unsafe_allow_html=True)
    if "df_raw" not in st.session_state:
        st.warning("⚠️ Upload dataset dulu di tab **Dataset**.")
    else:
        df_raw = st.session_state["df_raw"]
        text_cols = [COL_ISI] if COL_ISI in df_raw.columns else []
        for c in df_raw.columns:
            if c not in text_cols and df_raw[c].dtype == "object":
                if df_raw[c].astype(str).str.len().mean() > 50:
                    text_cols.append(c)
        if not text_cols:
            text_cols = list(df_raw.select_dtypes("object").columns)
        cat_cols = [COL_KATEGORI] if COL_KATEGORI in df_raw.columns else []
        for c in df_raw.columns:
            if c not in cat_cols and df_raw[c].dtype == "object":
                if 2 <= df_raw[c].nunique() <= 20:
                    cat_cols.append(c)
        if not cat_cols:
            cat_cols = list(df_raw.select_dtypes("object").columns)
        st.markdown("")
        idx_isi = text_cols.index(COL_ISI) if COL_ISI in text_cols else 0
        col_isi_sel = text_cols[idx_isi]
        idx_kat = cat_cols.index(COL_KATEGORI) if COL_KATEGORI in cat_cols else 0
        col_kat_sel = st.selectbox("Kolom kategori:", options=cat_cols, index=idx_kat)
        unique_cats   = df_raw[col_kat_sel].dropna().astype(str).str.lower().unique()
        default_cats  = [c for c in ["ekonomi","teknologi","olahraga","politik"] if c in unique_cats]
        selected_cats = st.multiselect("Filter kategori yang akan diproses:",
            options=sorted(unique_cats), default=default_cats if default_cats else list(unique_cats))
        if not selected_cats:
            selected_cats = list(unique_cats)
        with st.expander("Opsi Lanjutan"):
            oc1, oc2, oc3 = st.columns(3)
            do_stem     = oc1.checkbox("Gunakan stemming (Sastrawi)", value=True)
            remove_dup  = oc2.checkbox("Hapus dokumen duplikat", value=False,
                help="Notebook penelitian TIDAK menghapus duplikat dari data pemodelan (deteksi duplikat di notebook sifatnya hanya diagnostik/informasi). "
                     "Biarkan OFF (default) agar hasil sama persis dengan notebook (4.000 dokumen). Centang hanya jika ingin eksperimen data bersih.")
            min_tok_len = oc3.number_input("Panjang minimal token", min_value=2, value=3, step=1)
        st.markdown("")
        if st.button("▶ Jalankan Preprocessing", type="primary", use_container_width=True):
            stemmer, all_sw = get_stemmer_stopwords()
            df = df_raw.copy()
            awal = len(df)
            df[col_isi_sel] = df[col_isi_sel].astype(str)
            before = len(df)
            df.dropna(subset=[col_isi_sel, col_kat_sel], inplace=True)
            drop_na = before - len(df)
            df.reset_index(drop=True, inplace=True)
            df = df[df[col_kat_sel].astype(str).str.lower().isin([c.lower() for c in selected_cats])]
            df.reset_index(drop=True, inplace=True)
            drop_dup = 0
            if remove_dup:
                before = len(df)
                df = df.drop_duplicates(subset=[col_isi_sel])
                drop_dup = before - len(df)
                df.reset_index(drop=True, inplace=True)
            before = len(df)
            df = df[df[col_isi_sel].str.strip() != ""].reset_index(drop=True)
            drop_empty = before - len(df)
            if len(df) == 0:
                st.error("❌ Tidak ada data setelah filtering.")
                st.stop()
            prog = st.progress(0, "Memulai preprocessing...")
            t0   = time.time()
            cache: dict = {}
            tokens_list = []
            for i, text in enumerate(df[col_isi_sel]):
                toks = full_preprocessing(text, stemmer, all_sw, cache, do_stem=do_stem)
                toks = [t for t in toks if len(t) >= min_tok_len]
                tokens_list.append(toks)
                if (i+1) % 50 == 0 or i+1 == len(df):
                    prog.progress((i+1)/len(df), f"Memproses dokumen {i+1}/{len(df)}...")
            elapsed = time.time() - t0
            prog.progress(1.0, f"Selesai dalam {elapsed:.1f} detik!")
            df["tokens"]      = tokens_list
            df["teks_bersih"] = [" ".join(t) for t in tokens_list]
            df = df[df["teks_bersih"] != ""].reset_index(drop=True)
            df["panjang_asli"]   = df[col_isi_sel].apply(lambda x: len(str(x).split()))
            df["panjang_bersih"] = df["tokens"].apply(len)
            all_tok_before = df[col_isi_sel].apply(lambda x: str(x).split()).explode()
            all_tok_after  = df["tokens"].explode().dropna()
            reduksi        = int(round(100*(1 - len(all_tok_after)/max(len(all_tok_before),1))))
            st.session_state.update({
                "df": df, "col_kat": col_kat_sel, "col_isi": col_isi_sel,
                "token_list": df["tokens"].tolist(), "all_stopwords": all_sw,
                "stemmer": stemmer, "all_tok_before": all_tok_before, "all_tok_after": all_tok_after,
            })
            st.success(f"Preprocessing selesai dalam **{elapsed:.1f} detik**. Dokumen akhir: **{len(df):,}**")
            st.markdown('<div class="section-header">Statistik Preprocessing</div>', unsafe_allow_html=True)
            sm1,sm2,sm3,sm4,sm5 = st.columns(5)
            for col_m, val, lbl, cls in [
                (sm1, f"{len(df):,}", "Jumlah Dokumen", ""),
                (sm2, f"{len(all_tok_before):,}", "Kata Sebelum", ""),
                (sm3, f"{len(all_tok_after):,}", "Kata Sesudah", "metric-green"),
                (sm4, f"{all_tok_after.nunique():,}", "Kata Unik", "metric-purple"),
                (sm5, f"{reduksi}%", "Rasio Kompresi Token", "metric-orange"),
            ]:
                col_m.markdown(f'<div class="metric-card {cls}"><div class="val">{val}</div>'
                               f'<div class="lbl">{lbl}</div></div>', unsafe_allow_html=True)
            st.markdown("")
            stats = {
                "Keterangan": [
                    "Jumlah dokumen berita", "Total kata SEBELUM preprocessing",
                    "Total kata SESUDAH preprocessing", "Kata unik SEBELUM preprocessing",
                    "Kata unik SESUDAH preprocessing", "Rata-rata kata per dok (sebelum)",
                    "Rata-rata token per dok (sesudah)", "Token minimum dalam 1 dokumen",
                    "Token maksimum dalam 1 dokumen", "Waktu preprocessing (detik)",
                    "Rasio kompresi token setelah preprocessing",
                ],
                "Nilai": [
                    f"{len(df):,}", f"{len(all_tok_before):,}", f"{len(all_tok_after):,}",
                    f"{all_tok_before.nunique():,}", f"{all_tok_after.nunique():,}",
                    f"{df['panjang_asli'].mean():.1f}", f"{df['panjang_bersih'].mean():.1f}",
                    f"{df['panjang_bersih'].min():,}", f"{df['panjang_bersih'].max():,}",
                    f"{elapsed:.2f}", f"{reduksi}%",
                ]
            }
            st.dataframe(pd.DataFrame(stats).set_index("Keterangan"), use_container_width=True)
            with st.expander("Contoh Hasil Preprocessing (dokumen pertama)"):
                st.markdown(f"**Teks asli:** `{str(df[col_isi_sel].iloc[0])[:120]}...`")
                st.markdown(f"**Token hasil:** `{df['tokens'].iloc[0][:15]}`")
                st.caption("Setiap elemen dalam list = 1 token kata hasil preprocessing")
            fig_hist, ax_h = plt.subplots(figsize=(10, 4))
            fig_hist.patch.set_facecolor("#f8f9ff")
            x_max     = int(np.percentile(df["panjang_bersih"], 99))
            data_plot = df["panjang_bersih"][df["panjang_bersih"] <= x_max]
            counts, edges, patches = ax_h.hist(data_plot, bins=25, color=BLUE, alpha=0.85, edgecolor="white")
            for count, edge_left, edge_right in zip(counts, edges[:-1], edges[1:]):
                if count > 0:
                    ax_h.text((edge_left+edge_right)/2, count+max(counts)*0.01,
                              f"{int(count):,}", ha="center", va="bottom", fontsize=7.5, color="#1e3a5f", fontweight="600")
            ax_h.set_xlabel("Panjang Dokumen (token)", fontsize=10)
            ax_h.set_ylabel("Frekuensi (jumlah dokumen)", fontsize=10)
            ax_h.set_title("Distribusi Panjang Dokumen Setelah Preprocessing", fontweight="bold")
            ax_h.set_xlim(left=0, right=x_max)
            ax_h.set_ylim(0, max(counts) * 1.15)
            set_ax_style(ax_h)
            plt.tight_layout()
            st.pyplot(fig_hist, use_container_width=True)
            st.markdown("**Top-20 Kata Setelah Preprocessing**")
            freq  = Counter(all_tok_after.dropna().tolist())
            top20 = freq.most_common(20)
            df_top = pd.DataFrame(top20, columns=["Kata", "Frekuensi"])
            df_top.index += 1
            col_t20, col_bar = st.columns([1, 2])
            with col_t20:
                st.dataframe(df_top, use_container_width=True, height=420)
            with col_bar:
                fig_t20, ax_t20 = plt.subplots(figsize=(6, 5))
                fig_t20.patch.set_facecolor("#f8f9ff")
                words_r = [w for w, _ in reversed(top20)]
                freqs_r = [f for _, f in reversed(top20)]
                cb_bar  = plt.cm.Blues(np.linspace(0.4, 0.9, len(words_r)))
                ax_t20.barh(words_r, freqs_r, color=cb_bar)
                ax_t20.set_title("Top-20 Kata Terbanyak", fontweight="bold")
                ax_t20.set_xlabel("Frekuensi"); set_ax_style(ax_t20)
                plt.tight_layout()
                st.pyplot(fig_t20, use_container_width=True)
            st.markdown("**Top-5 Kata TF-IDF per Kategori**")
            try:
                tv = TfidfVectorizer(max_features=max_feat, min_df=5, max_df=0.90, ngram_range=(1, 1))
                tm = tv.fit_transform(df["teks_bersih"])
                vv = tv.get_feature_names_out()
                tpc = {}
                for kat in df[col_kat_sel].unique():
                    idx = df[df[col_kat_sel] == kat].index
                    sub = tm[idx]
                    mean_t = np.asarray(sub.mean(axis=0)).flatten()
                    top_i  = mean_t.argsort()[::-1][:5]
                    tpc[kat] = [vv[j] for j in top_i]
                df_tpc = pd.DataFrame(tpc)
                df_tpc.index = [f"#{i+1}" for i in range(len(df_tpc))]
                st.dataframe(df_tpc, use_container_width=True)
            except Exception as e:
                st.warning(f"Preview TF-IDF per kategori gagal: {e}")


