# TAB 4 — HASIL MODEL
# ════════════════════════════════════════════════════════════════════════════
with tab4:
    st.markdown('<div class="section-header">Hasil Pemodelan Topik LDA & NMF</div>', unsafe_allow_html=True)
    if "df" not in st.session_state:
        st.warning("⚠️ Jalankan Preprocessing dulu di tab **Preprocessing**.")
    else:
        df         = st.session_state["df"]
        token_list = st.session_state["token_list"]
        col_kat    = st.session_state["col_kat"]
        if st.button("▶ Latih Model LDA + NMF", type="primary", use_container_width=True):
            with st.spinner("Membangun matriks TF-IDF..."):
                tv    = TfidfVectorizer(max_features=max_feat, min_df=5, max_df=0.90, ngram_range=(1, 1))
                tmat  = tv.fit_transform(df["teks_bersih"])
                vocab = tv.get_feature_names_out()
                id2w  = corpora.Dictionary(token_list)
                id2w.filter_extremes(no_below=5, no_above=0.90)
                bow   = [id2w.doc2bow(d) for d in token_list]
            sparsity = 1 - tmat.nnz / (tmat.shape[0] * tmat.shape[1])
            tm1, tm2, tm3 = st.columns(3)
            tm1.markdown(f'<div class="metric-card"><div class="val">{tmat.shape[0]:,}</div><div class="lbl">Jumlah Berita yang Diproses</div></div>', unsafe_allow_html=True)
            tm2.markdown(f'<div class="metric-card metric-green"><div class="val">{tmat.shape[1]:,}</div><div class="lbl">Jumlah Kata Unik yang Dipakai Model</div></div>', unsafe_allow_html=True)
            tm3.markdown(f'<div class="metric-card metric-orange"><div class="val">{sparsity:.2%}</div><div class="lbl">Kepadatan Matriks (Sel Bernilai Nol)</div></div>', unsafe_allow_html=True)
            st.markdown("---")
            prog_lda = st.progress(0, "Melatih model LDA...")
            t_lda_s  = time.time()
            alpha_v   = float(lda_alpha) if lda_alpha not in ["symmetric","auto"] else lda_alpha
            lda_model = LdaModel(corpus=bow, id2word=id2w, num_topics=n_topics, random_state=RANDOM_SEED,
                                  passes=lda_passes, iterations=lda_iterations, alpha=alpha_v, eta=float(lda_eta), per_word_topics=True)
            t_lda_e = time.time()
            prog_lda.progress(1.0, f"LDA selesai dalam {t_lda_e-t_lda_s:.1f} detik!")
            with st.spinner("Menghitung Topic Coherence LDA..."):
                cm_lda    = CoherenceModel(model=lda_model, texts=token_list, dictionary=id2w, coherence="c_v", processes=1)
                coh_lda   = cm_lda.get_coherence()
                coh_lda_l = cm_lda.get_coherence_per_topic()
            log_perp_lda = -lda_model.log_perplexity(bow)
            perp_lda     = np.exp(log_perp_lda)
            lda_topics = []
            for i in range(n_topics):
                terms = lda_model.show_topic(i, topn=n_top_words)
                lda_topics.append(([w for w, _ in terms], [float(p) for _, p in terms]))
            df["lda_topik_dominan"] = [max(lda_model.get_document_topics(b, minimum_probability=0), key=lambda x: x[1])[0] for b in bow]
            df["lda_topik_label"]   = [f"Topik {t+1}" for t in df["lda_topik_dominan"]]
            prog_nmf = st.progress(0, "Melatih model NMF...")
            t_nmf_s  = time.time()
            nmf_model = NMF(n_components=n_topics, init=nmf_init, max_iter=nmf_iter, solver="cd", random_state=RANDOM_SEED, l1_ratio=0.0)
            W = nmf_model.fit_transform(tmat)
            H = nmf_model.components_
            t_nmf_e = time.time()
            prog_nmf.progress(1.0, f"NMF selesai dalam {t_nmf_e-t_nmf_s:.2f} detik!")
            nmf_topics_words = [[vocab[j] for j in H[i].argsort()[::-1][:n_top_words]] for i in range(n_topics)]
            with st.spinner("Menghitung Topic Coherence NMF..."):
                cm_nmf    = CoherenceModel(topics=nmf_topics_words, texts=token_list, dictionary=id2w, coherence="c_v", processes=1)
                coh_nmf   = cm_nmf.get_coherence()
                coh_nmf_l = cm_nmf.get_coherence_per_topic()
            recon_err    = nmf_model.reconstruction_err_
            n_elem       = tmat.shape[0] * tmat.shape[1]
            log_perp_nmf = -np.log(recon_err / n_elem + 1e-10)
            nmf_topics = []
            for i in range(n_topics):
                top_i = H[i].argsort()[::-1][:n_top_words]
                nmf_topics.append(([vocab[j] for j in top_i], [float(H[i][j]) for j in top_i]))
            df["nmf_topik_dominan"] = W.argmax(axis=1)
            df["nmf_topik_label"]   = [f"Topik {t+1}" for t in W.argmax(axis=1)]
            df["nmf_bobot_dominan"] = W.max(axis=1).round(4)
            st.session_state.update({
                "lda_model": lda_model, "nmf_model": nmf_model,
                "lda_topics": lda_topics, "nmf_topics": nmf_topics,
                "coh_lda": coh_lda, "coh_nmf": coh_nmf,
                "coh_lda_l": coh_lda_l, "coh_nmf_l": coh_nmf_l,
                "log_perp_lda": log_perp_lda, "perp_lda": perp_lda,
                "log_perp_nmf": log_perp_nmf, "recon_err": recon_err,
                "waktu_lda": t_lda_e-t_lda_s, "waktu_nmf": t_nmf_e-t_nmf_s,
                "vocab": vocab, "W": W, "H": H, "tmat": tmat, "id2w": id2w, "bow": bow, "df_processed": df,
            })
            st.success("Pemodelan LDA dan NMF berhasil diselesaikan!")
        if "lda_topics" in st.session_state:
            lt = st.session_state["lda_topics"]
            nt = st.session_state["nmf_topics"]
            cl = st.session_state["coh_lda_l"]
            cn = st.session_state["coh_nmf_l"]
            st.markdown("---")
            res_lda, res_nmf = st.tabs(["Hasil LDA", "Hasil NMF"])
            with res_lda:
                ml1,ml2,ml3,ml4 = st.columns(4)
                for col_m, val, lbl, cls in [
                    (ml1, f"{st.session_state['coh_lda']:.4f}", "Nilai Koherensi Topik (Cv)", "metric-green"),
                    (ml2, f"{st.session_state['log_perp_lda']:.4f}", "Log-Perplexity LDA<br>(↓ lebih kecil = lebih baik)", "metric-orange"),
                    (ml3, f"{st.session_state['perp_lda']:,.2f}", "Perplexity LDA", ""),
                    (ml4, f"{st.session_state['waktu_lda']:.1f} detik", "Waktu Pelatihan Model", "metric-purple"),
                ]:
                    col_m.markdown(f'<div class="metric-card {cls}"><div class="val">{val}</div><div class="lbl">{lbl}</div></div>', unsafe_allow_html=True)
                st.markdown("")
                rows_lda = []
                for i, (words, _) in enumerate(lt):
                    cv = cl[i] if i < len(cl) else 0
                    rows_lda.append({"Topik": f"Topik {i+1}", "Kata Dominan": ", ".join(words), "Cv": round(cv,4)})
                st.dataframe(pd.DataFrame(rows_lda).set_index("Topik"), use_container_width=True)
                st.markdown("**Distribusi Dokumen per Topik LDA**")
                if "df_processed" in st.session_state:
                    dist_lda = st.session_state["df_processed"]["lda_topik_label"].value_counts()
                    fig_dl, ax_dl = plt.subplots(figsize=(7,3))
                    fig_dl.patch.set_facecolor("#f8f9ff")
                    ax_dl.bar(dist_lda.index, dist_lda.values, color=BLUE, alpha=0.85)
                    ax_dl.set_title("Jumlah Dokumen per Topik (LDA)", fontweight="bold")
                    ax_dl.set_xlabel("Topik Dominan"); ax_dl.set_ylabel("Jumlah Dokumen")
                    set_ax_style(ax_dl)
                    for x_bar, v in zip(ax_dl.patches, dist_lda.values):
                        ax_dl.text(x_bar.get_x()+x_bar.get_width()/2, v+5, str(v), ha="center", fontsize=10, fontweight="bold")
                    plt.tight_layout()
                    st.pyplot(fig_dl, use_container_width=True)
                st.pyplot(plot_topic_words("LDA", lt, cl), use_container_width=True)
            with res_nmf:
                mn1,mn2,mn3,mn4 = st.columns(4)
                for col_m, val, lbl, cls in [
                    (mn1, f"{st.session_state['coh_nmf']:.4f}", "Nilai Koherensi Topik (Cv)", "metric-green"),
                    (mn2, f"{st.session_state['log_perp_nmf']:.4f}", "Log-Perplexity NMF<br>(Frobenius Norm)", "metric-orange"),
                    (mn3, f"{st.session_state['recon_err']:.4f}", "Galat Rekonstruksi<br>‖X − WH‖", ""),
                    (mn4, f"{st.session_state['waktu_nmf']:.1f} detik", "Waktu Pelatihan Model", "metric-purple"),
                ]:
                    col_m.markdown(f'<div class="metric-card {cls}"><div class="val">{val}</div><div class="lbl">{lbl}</div></div>', unsafe_allow_html=True)
                st.markdown("")
                rows_nmf = []
                for i, (words, _) in enumerate(nt):
                    cv = cn[i] if i < len(cn) else 0
                    rows_nmf.append({"Topik": f"Topik {i+1}", "Kata Dominan": ", ".join(words), "Cv": round(cv,4)})
                st.dataframe(pd.DataFrame(rows_nmf).set_index("Topik"), use_container_width=True)
                st.markdown("**Distribusi Dokumen per Topik NMF**")
                if "df_processed" in st.session_state:
                    dist_nmf = st.session_state["df_processed"]["nmf_topik_label"].value_counts()
                    fig_dn, ax_dn = plt.subplots(figsize=(7,3))
                    fig_dn.patch.set_facecolor("#f8f9ff")
                    ax_dn.bar(dist_nmf.index, dist_nmf.values, color=ORANGE, alpha=0.85)
                    ax_dn.set_title("Jumlah Dokumen per Topik (NMF)", fontweight="bold")
                    ax_dn.set_xlabel("Topik Dominan"); ax_dn.set_ylabel("Jumlah Dokumen")
                    set_ax_style(ax_dn)
                    for x_bar, v in zip(ax_dn.patches, dist_nmf.values):
                        ax_dn.text(x_bar.get_x()+x_bar.get_width()/2, v+5, str(v), ha="center", fontsize=10, fontweight="bold")
                    plt.tight_layout()
                    st.pyplot(fig_dn, use_container_width=True)
                st.pyplot(plot_topic_words("NMF", nt, cn), use_container_width=True)


# ════════════════════════════════════════════════════════════════════════════
# TAB 5 — PERBANDINGAN
# ════════════════════════════════════════════════════════════════════════════
with tab5:
    st.markdown('<div class="section-header">Perbandingan LDA vs NMF</div>', unsafe_allow_html=True)
    if "coh_lda" not in st.session_state:
        st.warning("⚠️ Jalankan model dulu di tab **Hasil Model**.")
    else:
        coh_lda = st.session_state["coh_lda"]
        coh_nmf = st.session_state["coh_nmf"]
        cl      = st.session_state["coh_lda_l"]
        cn      = st.session_state["coh_nmf_l"]
        w_lda   = st.session_state["waktu_lda"]
        w_nmf   = st.session_state["waktu_nmf"]
        lp_lda  = st.session_state["log_perp_lda"]
        lp_nmf  = st.session_state["log_perp_nmf"]
        rc_nmf  = st.session_state["recon_err"]
        pxlda   = st.session_state["perp_lda"]
        pemenang = "NMF" if coh_nmf > coh_lda else "LDA"
        selisih  = abs(coh_nmf - coh_lda)
        p1, p2, p3, p4 = st.columns(4)
        cls_p = "metric-orange" if pemenang == "NMF" else "metric-green"
        for col_m, val, lbl, cls in [
            (p1, pemenang, "Metode Terbaik (Cv)", cls_p),
            (p2, f"{selisih:.4f}", "Selisih Nilai Koherensi", ""),
            (p3, f"{w_lda:.1f} detik", "Lama Pelatihan LDA", "metric-purple"),
            (p4, f"{w_nmf:.1f} detik", "Lama Pelatihan NMF", "metric-green"),
        ]:
            col_m.markdown(f'<div class="metric-card {cls}"><div class="val">{val}</div><div class="lbl">{lbl}</div></div>', unsafe_allow_html=True)
        st.markdown("")
        st.markdown("#### Perbandingan Coherence per Topik")
        rows_cmp = []
        for i in range(n_topics):
            lv = cl[i] if i < len(cl) else 0
            nv = cn[i] if i < len(cn) else 0
            rows_cmp.append({"Topik": f"Topik {i+1}", "LDA (Cv)": round(lv,4), "NMF (Cv)": round(nv,4),
                             "Selisih": round(nv-lv,4), "Unggul": "NMF ✓" if nv >= lv else "LDA ✓"})
        rows_cmp.append({"Topik": "**Rata-rata**", "LDA (Cv)": round(coh_lda,4), "NMF (Cv)": round(coh_nmf,4),
                         "Selisih": round(coh_nmf-coh_lda,4), "Unggul": "NMF ✓" if coh_nmf >= coh_lda else "LDA ✓"})
        st.dataframe(pd.DataFrame(rows_cmp).set_index("Topik"), use_container_width=True)
        st.pyplot(plot_coherence_comparison(coh_lda, coh_nmf, cl, cn, n_topics), use_container_width=True)
        st.markdown("#### Tabel Ringkasan Perbandingan")
        summary = pd.DataFrame({
            "Indikator": ["Rata-rata Koherensi Topik (Cv)", "Log-Perplexity", "Perplexity / Galat Rekonstruksi",
                          "Lama Pelatihan Model (detik)", "Ketajaman Distribusi Topik", "Kemudahan Baca Topik"],
            "LDA": [f"{coh_lda:.4f}", f"{lp_lda:.4f} (positif, ↓ lebih baik)", f"{pxlda:,.2f}",
                    f"{w_lda:.1f} detik", "Sedang (distribusi probabilistik)", "Baik (kata bermakna)"],
            "NMF": [f"{coh_nmf:.4f}", f"{lp_nmf:.4f} (berbasis Frobenius norm)", f"Galat Rekonstruksi = {rc_nmf:.4f}",
                    f"{w_nmf:.1f} detik", "Tinggi (distribusi deterministik)", "Sangat baik (topik lebih tajam)"],
            "Unggul": ["NMF ✓" if coh_nmf > coh_lda else "LDA ✓", "Tidak dapat dibandingkan langsung",
                       "Metrik berbeda", "NMF ✓" if w_nmf < w_lda else "LDA ✓", "NMF ✓", "NMF ✓"],
        }).set_index("Indikator")
        st.dataframe(summary, use_container_width=True)
        st.info("""
        **ℹ️ Catatan Log-Perplexity:**
        - **LDA**: Log-Perplexity dihitung dari Gensim (nilai positif). Semakin kecil = model semakin baik dalam mengenali pola dokumen.
        - **NMF**: Log-Perplexity dihitung dari galat rekonstruksi matriks. Tidak bisa dibandingkan langsung dengan LDA karena cara hitungnya berbeda.
        - Ukuran utama yang dipakai untuk menentukan metode terbaik dalam penelitian ini adalah **Nilai Koherensi Topik (Cv)**.
        """)
        st.markdown("---")
        st.markdown("#### Baseline Hasil Notebook Penelitian (Skripsi)")
        st.caption("Hasil asli dari notebook penelitian (dataset 4.000 berita, K=4). Bandingkan dengan hasil re-training di atas untuk mengecek konsistensi/reproduktifitas.")
        bl1, bl2, bl3, bl4 = st.columns(4)
        for col_m, val, lbl, cls in [
            (bl1, f"{STATIC['lda_cv']:.4f} / {STATIC['nmf_cv']:.4f}", "Cv Baseline (LDA / NMF)", "metric-green"),
            (bl2, f"{STATIC['log_perp_lda']:.4f} / {STATIC['log_perp_nmf']:.4f}", "Log-Perplexity Baseline (LDA / NMF)", "metric-orange"),
            (bl3, f"{STATIC['waktu_lda']:.1f}s / {STATIC['waktu_nmf']:.1f}s", "Waktu Latih Baseline (LDA / NMF)", "metric-purple"),
            (bl4, "NMF" if STATIC["nmf_cv"] > STATIC["lda_cv"] else "LDA", "Metode Unggul Baseline (Cv)", ""),
        ]:
            col_m.markdown(f'<div class="metric-card {cls}"><div class="val" style="font-size:1.1rem;">{val}</div><div class="lbl">{lbl}</div></div>', unsafe_allow_html=True)
        df_baseline_stem = pd.DataFrame({
            "Pipeline": ["Dengan Stemming", "Tanpa Stemming"],
            "LDA Cv": [STATIC["stem_results"]["Dengan Stemming"]["LDA_Coherence"], STATIC["stem_results"]["Tanpa Stemming"]["LDA_Coherence"]],
            "NMF Cv": [STATIC["stem_results"]["Dengan Stemming"]["NMF_Coherence"], STATIC["stem_results"]["Tanpa Stemming"]["NMF_Coherence"]],
        }).set_index("Pipeline")
        bc1, bc2 = st.columns([1, 1])
        with bc1:
            st.markdown("**Perbandingan Dengan vs Tanpa Stemming (Baseline)**")
            st.dataframe(df_baseline_stem, use_container_width=True)
        with bc2:
            st.markdown("**Label Topik Baseline (K=4)**")
            df_baseline_labels = pd.DataFrame({
                "Topik": [f"Topik {i}" for i in range(1, 5)],
                "Label LDA": [STATIC["lda_topics_label"][i] for i in range(1, 5)],
                "Label NMF": [STATIC["nmf_topics_label"][i] for i in range(1, 5)],
            }).set_index("Topik")
            st.dataframe(df_baseline_labels, use_container_width=True)
        if "df_processed" in st.session_state:
            st.markdown("---")
            st.markdown("#### Distribusi Topik Dominan per Kategori Aktual")
            df_p  = st.session_state["df_processed"]
            col_k = st.session_state["col_kat"]
            try:
                fig_cm, axes_cm = plt.subplots(1, 2, figsize=(14, 5))
                fig_cm.patch.set_facecolor("#f8f9ff")
                label_t = [f"Topik {i+1}" for i in range(n_topics)]
                for ax, col_t, lbl_m, cmap_m in [
                    (axes_cm[0], "lda_topik_dominan", "LDA", "Blues"),
                    (axes_cm[1], "nmf_topik_dominan", "NMF", "Oranges"),
                ]:
                    ct = pd.crosstab(df_p[col_k], df_p[col_t].map(lambda x: f"Topik {x+1}"),
                                     rownames=["Kategori Aktual"], colnames=["Topik Model"])
                    for t in label_t:
                        if t not in ct.columns: ct[t] = 0
                    ct = ct[label_t]
                    sns.heatmap(ct, annot=True, fmt="d", cmap=cmap_m, linewidths=0.5, ax=ax, cbar_kws={"label": "Jumlah Dokumen"})
                    ax.set_title(f"Distribusi Topik — {lbl_m}", fontweight="bold")
                    ax.tick_params(axis="x", rotation=20); ax.tick_params(axis="y", rotation=0)
                plt.tight_layout()
                st.pyplot(fig_cm, use_container_width=True)
            except Exception as e:
                st.warning(f"Tidak dapat menampilkan confusion matrix: {e}")


